// ==UserScript==
// @name         JL: PPM Contract Customer Report
// @namespace    https://go.joblogic.com/
// @version      4.8
// @downloadURL https://raw.githubusercontent.com/joesegal-ops/TMJSScripts/main/JL%20PPMs/ppm-customer-report.user.js
// @updateURL  https://raw.githubusercontent.com/joesegal-ops/TMJSScripts/main/JL%20PPMs/ppm-customer-report.user.js
// @description  Generate a branded Untitled Projects PPM matrix report — services as rows, months as columns, colour-coded completion status. Share with the customer monthly. v4.1: collapses to a launcher button in the shared dock (drag to reorder).
// @match        https://go.joblogic.com/PPMContract/Detail/*
// @grant        none
// @run-at       document-idle
// ==/UserScript==

(function () {
    'use strict';

    // ===== Shared JL userscript launcher dock (identical in every script) =====
    const JL_DOCK_ID = 'jl-userscript-dock', JL_ORDER_KEY = 'jl-userscript-dock-order', JL_MIN_KEY = 'jl-userscript-dock-min', JL_TOP_KEY = 'jl-userscript-dock-top';
    const JL_BTN_CSS = 'color:#fff;padding:7px 13px;border-radius:4px;border:1px solid transparent;cursor:grab;font-family:"Open Sans",sans-serif;font-size:14px;box-shadow:0 1px 3px rgba(0,0,0,.25);white-space:nowrap;';
    const jlDockList = () => document.getElementById('jl-userscript-dock-list');
    function jlReadOrder() { try { return JSON.parse(localStorage.getItem(JL_ORDER_KEY)) || []; } catch (e) { return []; } }
    function jlSaveOrder() { const l = jlDockList(); if (!l) return; localStorage.setItem(JL_ORDER_KEY, JSON.stringify([...l.children].map(b => b.dataset.scriptId).filter(Boolean))); }
    function jlApplyOrder() { const l = jlDockList(); if (!l) return; [...l.children].sort((a, b) => { const o = jlReadOrder(); let ia = o.indexOf(a.dataset.scriptId), ib = o.indexOf(b.dataset.scriptId); if (ia < 0) ia = 1e9; if (ib < 0) ib = 1e9; return ia - ib; }).forEach(b => l.appendChild(b)); }
    function jlAfter(l, y) { let c = { o: -Infinity, el: null }; for (const el of l.querySelectorAll('button:not(.jl-dragging)')) { const r = el.getBoundingClientRect(); const off = y - (r.top + r.height / 2); if (off < 0 && off > c.o) c = { o: off, el }; } return c.el; }
    function jlSetDockMin(min) { const l = jlDockList(), t = document.getElementById('jl-userscript-dock-toggle'); if (l) l.style.display = min ? 'none' : 'flex'; if (t) t.textContent = (min ? '▸' : '▾') + ' Advanced Controls'; try { localStorage.setItem(JL_MIN_KEY, min ? '1' : '0'); } catch (e) {} }
    function jlGetDock() {
        if (!document.getElementById('jl-dock-style')) { const st = document.createElement('style'); st.id = 'jl-dock-style'; st.textContent = '#jl-userscript-dock button:hover{filter:brightness(1.18);}'; (document.head || document.documentElement).appendChild(st); }
        let d = document.getElementById(JL_DOCK_ID);
        if (!d) { d = document.createElement('div'); d.id = JL_DOCK_ID; document.body.appendChild(d); }
        d.style.cssText = 'position:fixed;top:80px;right:8px;z-index:100000;display:flex;flex-direction:column;gap:8px;align-items:flex-end;';
        const savedTop = localStorage.getItem(JL_TOP_KEY); if (savedTop !== null) d.style.top = savedTop + 'px';
        let t = document.getElementById('jl-userscript-dock-toggle');
        if (!t) {
            t = document.createElement('button');
            t.id = 'jl-userscript-dock-toggle';
            t.title = 'Drag to move up/down • click to expand/collapse';
            t.style.cssText = JL_BTN_CSS + 'background:#072d3d;border-color:#072d3d;touch-action:none;';
            let drag = null;
            t.addEventListener('pointerdown', e => { drag = { y: e.clientY, top: d.getBoundingClientRect().top, moved: false }; try { t.setPointerCapture(e.pointerId); } catch (x) {} t.style.cursor = 'grabbing'; e.preventDefault(); });
            t.addEventListener('pointermove', e => { if (!drag) return; const dy = e.clientY - drag.y; if (Math.abs(dy) > 4) drag.moved = true; if (drag.moved) { const top = Math.max(4, Math.min(window.innerHeight - 40, drag.top + dy)); d.style.top = top + 'px'; } });
            const endDrag = e => { if (!drag) return; const moved = drag.moved; drag = null; t.style.cursor = 'grab'; try { t.releasePointerCapture(e.pointerId); } catch (x) {} if (moved) { try { localStorage.setItem(JL_TOP_KEY, parseInt(d.style.top, 10)); } catch (x) {} } else { jlSetDockMin(jlDockList().style.display !== 'none'); } };
            t.addEventListener('pointerup', endDrag);
            t.addEventListener('pointercancel', endDrag);
            d.appendChild(t);
        }
        let l = document.getElementById('jl-userscript-dock-list');
        if (!l) {
            l = document.createElement('div');
            l.id = 'jl-userscript-dock-list';
            l.style.cssText = 'display:flex;flex-direction:column;gap:8px;align-items:flex-end;';
            l.addEventListener('dragover', e => { e.preventDefault(); const dr = l.querySelector('.jl-dragging'); if (!dr) return; const a = jlAfter(l, e.clientY); if (a == null) l.appendChild(dr); else l.insertBefore(dr, a); });
            l.addEventListener('drop', e => { e.preventDefault(); jlSaveOrder(); });
            d.appendChild(l);
        }
        jlSetDockMin(localStorage.getItem(JL_MIN_KEY) !== '0');
        return d;
    }
    function jlDockButton(id, label, color, onClick) {
        jlGetDock();
        const l = jlDockList();
        let b = document.getElementById('jl-launch-' + id);
        if (b) return b;
        const bg = color || '#072d3d';
        b = document.createElement('button');
        b.id = 'jl-launch-' + id;
        b.dataset.scriptId = id;
        b.textContent = label;
        b.title = 'Show / hide ' + label + '  (drag to reorder)';
        b.draggable = true;
        b.style.cssText = JL_BTN_CSS + 'background:' + bg + ';border-color:' + bg + ';';
        b.addEventListener('click', () => { if (b.dataset.justDragged) { delete b.dataset.justDragged; return; } onClick(); });
        b.addEventListener('dragstart', () => { b.classList.add('jl-dragging'); b.style.opacity = '0.4'; });
        b.addEventListener('dragend', () => { b.classList.remove('jl-dragging'); b.style.opacity = '1'; b.dataset.justDragged = '1'; setTimeout(() => { delete b.dataset.justDragged; }, 60); jlSaveOrder(); });
        l.appendChild(b);
        jlApplyOrder();
        return b;
    }
    // Collapse a panel to a dock button. panelEl = the OUTERMOST element of the
    // script's floating UI. Returns the dock button.
    function jlRegisterPanel(panelEl, id, label, color) {
        const shown = (panelEl.style.display && panelEl.style.display !== 'none') ? panelEl.style.display : 'block';
        panelEl.style.display = 'none';
        const btn = jlDockButton(id, label, color, () => {
            const opening = panelEl.style.display === 'none';
            panelEl.style.display = opening ? shown : 'none';
            btn.style.boxShadow = opening ? '0 0 0 2px #fff, 0 1px 3px rgba(0,0,0,.25)' : '0 1px 3px rgba(0,0,0,.25)';
        });
        return btn;
    }
    // ===== end shared dock =====

    const SCRIPT_ID = 'ppm-customer-report';
    const SCRIPT_LABEL = '📊 PPM Customer Report';
    const SCRIPT_COLOR = '#4c9f01';

    // ─── Embedded logo (base64, self-contained) ─────────────────────────────
    const LOGO_B64 = '';

    if (window.__ppmReportLoaded) return;
    window.__ppmReportLoaded = true;

    const qs  = (s, r = document) => r.querySelector(s);
    const qsa = (s, r = document) => [...r.querySelectorAll(s)];

    // ─── Date helpers ─────────────────────────────────────────────────────────
    function parseUKDate(str) {
        if (!str) return null;
        const m = String(str).trim().match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+(\d{1,2}):(\d{2}))?/);
        if (!m) return null;
        const d = new Date(+m[3], +m[2] - 1, +m[1], m[4] ? +m[4] : 0, m[5] ? +m[5] : 0);
        return isNaN(d) ? null : d;
    }
    function monthKey(d) {
        return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
    }
    const SHORT_MON = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    function monthLabel(key) {
        const [y, m] = key.split('-');
        return `${SHORT_MON[+m - 1]} '${y.slice(2)}`;
    }

    // ─── Auto-categorise service descriptions ────────────────────────────────
    const CAT_RULES = [
        {
            name: 'Water Hygiene',
            accent: '#0097A7', bg: '#e0f7fa', border: '#80deea', text: '#006064',
            re: /water|flush|tmv|legionella|sentinel|temperature test|sampling|risk assess|annual review|chlorin/i
        },
        {
            name: 'Electrical',
            accent: '#FFAB40', bg: '#fff8e1', border: '#ffe082', text: '#e65100',
            re: /electric|lights|lighting|eicr|pat test|ups\b|power|emergency light|distribution board|consumer unit/i
        },
        {
            name: 'Fire Safety',
            accent: '#f43f5e', bg: '#fff1f2', border: '#fecdd3', text: '#9f1239',
            re: /fire alarm|fire door|sprinkler|extinguish|suppression|smoke|detection/i
        },
        {
            name: 'HVAC',
            accent: '#10b981', bg: '#ecfdf5', border: '#a7f3d0', text: '#065f46',
            re: /hvac|vrv|vrf|air.?con|a\/c|\bac\b|fan coil|chiller|heat pump|ahu|ventilation|cooling/i
        },
        {
            name: 'Mechanical',
            accent: '#8b5cf6', bg: '#f5f3ff', border: '#ddd6fe', text: '#4c1d95',
            re: /boiler|heating|gas|pump|plumb|plant|pressure|valve|pipework/i
        },
    ];
    const CAT_GENERAL = { name: 'General', accent: '#4285F4', bg: '#e8f0fe', border: '#aecbfa', text: '#1a73e8' };

    function categorise(desc) {
        for (const rule of CAT_RULES) {
            if (rule.re.test(desc)) return rule;
        }
        return CAT_GENERAL;
    }

    // ─── Contract meta ────────────────────────────────────────────────────────
    function readContractMeta() {
        const meta = { ref: '', planRef: '', site: '', customer: '', description: '' };

        // Contract number: most reliably from page title "PM0000622 - PPM Contract - JobLogic"
        const titleMatch = document.title.match(/^(PM\d+)/);
        if (titleMatch) meta.ref = titleMatch[1];
        // Fallback: H3 heading text
        if (!meta.ref) {
            const h3 = qs('h3');
            const h3m = h3 ? h3.textContent.match(/PM\d+/) : null;
            if (h3m) meta.ref = h3m[0];
        }

        // Plan Reference: #PlanReference input on the Details tab
        const planRefEl = qs('#PlanReference');
        if (planRefEl) meta.planRef = planRefEl.value.trim();

        // Site / customer: scan Details tab label→input pairs
        const detailTab = qs('#detailTab');
        if (detailTab) {
            for (const lbl of qsa('label', detailTab)) {
                const txt = lbl.textContent.toLowerCase().trim().replace(/[*:.]/g, '');
                const forId = lbl.getAttribute('for');
                if (!forId || forId === 'null') continue;
                const valEl = qs('#' + CSS.escape(forId));
                const val   = valEl ? (valEl.value || valEl.textContent || '').trim() : '';
                if (!val) continue;
                if (/^site\b/.test(txt) && !meta.site)             meta.site     = val;
                if (/customer|client/.test(txt) && !meta.customer) meta.customer = val;
            }
        }

        return meta;
    }

    // ─── Read duration (minutes) from an already-expanded visit row ──────────
    function readDurationFromScope(scope) {
        for (const lbl of qsa('label', scope)) {
            if (!/duration/i.test(lbl.textContent)) continue;
            const forId = lbl.getAttribute('for');
            const inp   = forId
                ? scope.querySelector('#' + CSS.escape(forId))
                : lbl.parentElement?.querySelector('input[type="number"], input[type="text"]');
            if (inp) {
                const v = parseFloat((inp.value || '').replace(/[^\d.]/g, ''));
                if (!isNaN(v) && v > 0) return v;
            }
        }
        return null;
    }

    // ─── Try to expand a row and read duration; collapses it again ───────────
    async function readDurationFromRow(row) {
        const details = row.querySelector('.visit-details');
        // Already expanded? Read immediately.
        if (details && getComputedStyle(details).display !== 'none' && details.childElementCount > 0) {
            return readDurationFromScope(details);
        }
        // Expand it
        const trigger = row.querySelector('.visit-info-description, .visit-info') || row;
        trigger.click();
        // Wait up to 400ms for content to render
        await new Promise(r => setTimeout(r, 400));
        const d2 = row.querySelector('.visit-details');
        const dur = (d2 && d2.childElementCount > 0) ? readDurationFromScope(d2) : null;
        // Collapse it again so the page looks untouched
        trigger.click();
        return dur;
    }

    // ─── Determine status given due date and duration ─────────────────────────
    // Joblogic shows one of: "Completed" (green) | "Allocated" (orange) | "New Job" (orange)
    // "Overdue" is not a Joblogic label — we calculate it from effectiveEnd.
    // Priority: complete > cancelled > overdue (date+duration past) > raised > pending
    function detectStatus(row, effectiveEnd) {
        const label     = qs('.label', row);
        const labelText = (label ? label.textContent : '').trim().toLowerCase();

        // 1. Complete
        if (/complet/.test(labelText)) return 'complete';

        // 2. Cancelled
        if (/cancel/.test(labelText)) return 'cancelled';

        // 3. Overdue: effectiveEnd (dueDate + duration) is in the past
        if (effectiveEnd && effectiveEnd < new Date()) return 'overdue';

        // 4. Raised / allocated / in-progress (future job that exists in Joblogic)
        if (/new.?job|allocat|in.?progress|open|raised|active/.test(labelText)) return 'raised';

        // 5. Fallback: row-level class (older Joblogic styling)
        const rc = row.className || '';
        if (/list-group-item-success/.test(rc)) return 'complete';
        if (/list-group-item-danger/.test(rc))  return 'overdue';
        if (/list-group-item-warning/.test(rc)) return 'raised';

        return 'pending';
    }

    // ─── Read all visits ──────────────────────────────────────────────────────
    // DOM structure (confirmed by inspection):
    //   li.list-group-item
    //     div.visit-info
    //       div.visit-info-description
    //         div.row
    //           div.col-md-4
    //             <b><a class="openJobDetail">PM0000622/020</a></b>
    //             span.ml12  ← due date "05/02/2026 08:00"
    //             [span.visit-info-description__label …task/asset counts…]
    //             <p>  ← description text (may have real \n line breaks)
    //           [other cols: hidden .dots spans, assignee, status label]
    //           div  ← label.label "Completed" / "Allocated" / "New Job"
    //     div.visit-details (display:none until expanded)
    async function readVisits() {
        const rows = qsa('#ppmVisits ul.list-group > li.list-group-item')
            .filter(r => r.offsetParent !== null);

        const visits = [];
        for (const row of rows) {
            // Description: directly in <p> — split on newlines, take first non-empty line
            const pEl = qs('p', row);
            const description = pEl
                ? (pEl.textContent.split('\n').map(l => l.trim()).filter(Boolean)[0] || 'PPM Visit')
                : 'PPM Visit';

            // Date: in span.ml12 e.g. "05/02/2026 08:00"
            const dateEl  = qs('span.ml12', row);
            const dueDate = dateEl ? parseUKDate(dateEl.textContent.trim()) : null;

            // Job ref and URL (a.openJobDetail carries the href to /Job/Detail/{id})
            const jobLink = qs('a.openJobDetail', row);
            const jobRef  = jobLink ? jobLink.textContent.trim() : '';
            const rawHref = jobLink ? (jobLink.getAttribute('href') || '') : '';
            // Make absolute so links work in the report window (which has no Joblogic base)
            const jobUrl  = rawHref && rawHref !== '#'
                ? (rawHref.startsWith('http') ? rawHref : 'https://go.joblogic.com' + rawHref)
                : '';

            // Effective end = dueDate + duration. Only bother expanding the row for
            // recently-past visits (within 30 days) where duration changes the verdict.
            let effectiveEnd = null;
            if (dueDate) {
                const now          = new Date();
                const msInPast     = now - dueDate;
                const thirtyDaysMs = 30 * 24 * 60 * 60 * 1000;

                if (msInPast > 0 && msInPast < thirtyDaysMs) {
                    const dur = await readDurationFromRow(row);
                    effectiveEnd = dur
                        ? new Date(dueDate.getTime() + dur * 60 * 1000)
                        : new Date(dueDate.getFullYear(), dueDate.getMonth(), dueDate.getDate(), 23, 59, 59);
                } else if (msInPast >= thirtyDaysMs) {
                    effectiveEnd = dueDate; // clearly in the past
                }
            }

            const status = detectStatus(row, effectiveEnd);
            visits.push({ dueDate, description, status, jobRef, jobUrl });
        }
        return visits;
    }

    // ─── HTML escaping ───────────────────────────────────────────────────────
    function esc(s) {
        return String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;')
            .replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
    }

    // fmtDays / mergeStatus removed — cells now render one dot per individual visit

    // ─── Generate the matrix report ─────────────────────────────────────────
    function generateReport(visits, meta) {
        const today = new Date(); today.setHours(0, 0, 0, 0);
        const thisMonthKey = monthKey(today);

        // ── Group visits by service description → month ──────────────────────
        const serviceMap = new Map(); // desc → { cat, months: { mk: { days, status } } }
        const monthSet   = new Set();

        for (const v of visits) {
            if (!v.dueDate) continue;
            const mk  = monthKey(v.dueDate);
            const day = v.dueDate.getDate();
            monthSet.add(mk);

            if (!serviceMap.has(v.description)) {
                serviceMap.set(v.description, { cat: categorise(v.description), months: {} });
            }
            const svc = serviceMap.get(v.description);
            if (!svc.months[mk]) svc.months[mk] = { visits: [] };
            svc.months[mk].visits.push({ day, status: v.status, jobRef: v.jobRef, jobUrl: v.jobUrl });
        }

        const sortedMonths = [...monthSet].sort();

        // ── Collect all categories present, in defined order ─────────────────
        const allCatDefs = [...CAT_RULES, CAT_GENERAL];
        const usedCats   = new Set([...serviceMap.values()].map(s => s.cat.name));
        const activeCats = allCatDefs.filter(c => usedCats.has(c.name));

        // ── Build service rows grouped under categories ───────────────────────
        const catGroups = {};
        for (const cat of activeCats) catGroups[cat.name] = [];
        for (const [desc, data] of serviceMap) {
            catGroups[data.cat.name].push({ desc, ...data });
        }
        // Sort services within each category alphabetically
        for (const arr of Object.values(catGroups)) arr.sort((a, b) => a.desc.localeCompare(b.desc));

        // ── Stats (count individual visits, not job×month cells) ─────────────
        let total = 0, complete = 0, overdue = 0;
        for (const [, svc] of serviceMap) {
            for (const cell of Object.values(svc.months)) {
                for (const v of cell.visits) {
                    total++;
                    if (v.status === 'complete') complete++;
                    else if (v.status === 'overdue') overdue++;
                }
            }
        }
        const upcoming = total - complete - overdue;
        const pct = total > 0 ? Math.round((complete / total) * 100) : 0;

        // ── This-month stats ──────────────────────────────────────────────────
        let mTotal = 0, mComplete = 0, mOverdue = 0;
        for (const [, svc] of serviceMap) {
            const cell = svc.months[thisMonthKey];
            if (!cell) continue;
            for (const v of cell.visits) {
                mTotal++;
                if (v.status === 'complete') mComplete++;
                else if (v.status === 'overdue') mOverdue++;
            }
        }
        const mUpcoming = mTotal - mComplete - mOverdue;
        const mPct      = mTotal > 0 ? Math.round((mComplete / mTotal) * 100) : 0;
        const thisMonthName = sortedMonths.includes(thisMonthKey) ? monthLabel(thisMonthKey) : '';

        const contractPeriod = sortedMonths.length >= 2
            ? `${monthLabel(sortedMonths[0])} – ${monthLabel(sortedMonths[sortedMonths.length - 1])}`
            : '';
        const genDate = today.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });

        // ── Cell renderer — one dot per individual visit ─────────────────────
        const CELL_CFG = {
            complete:  { bg: '#f0fdf4', icon: '✓', ic: '#16a34a', border: '#86efac', label: 'Complete'    },
            overdue:   { bg: '#fff1f2', icon: '!', ic: '#dc2626', border: '#fca5a5', label: 'Overdue'     },
            raised:    { bg: '#fff8e1', icon: '◎', ic: '#d97706', border: '#fcd34d', label: 'In Progress' },
            pending:   { bg: '#f8fafc', icon: '–', ic: '#94a3b8', border: '#cbd5e1', label: 'Scheduled'   },
            cancelled: { bg: '#f3f4f6', icon: '×', ic: '#9ca3af', border: '#d1d5db', label: 'Cancelled'   },
        };

        // Derive the aggregate cell background from its worst-case visit status
        const CELL_BG_RANK = { complete: 0, pending: 1, raised: 2, overdue: 3, cancelled: 1 };
        function cellBg(visits) {
            const worst = visits.reduce((acc, v) => {
                const s = v.status || 'pending';
                return (CELL_BG_RANK[s] ?? 1) > (CELL_BG_RANK[acc] ?? 0) ? s : acc;
            }, 'complete');
            return (CELL_CFG[worst] || CELL_CFG.pending).bg;
        }

        function renderCell(mk, cell) {
            const isCur  = mk === thisMonthKey;
            const sorted = [...cell.visits].sort((a, b) => a.day - b.day);
            const bg     = cellBg(cell.visits);

            const dots = sorted.map(v => {
                const cfg     = CELL_CFG[v.status] || CELL_CFG.pending;
                const tipText = v.jobRef
                    ? `${cfg.label} · ${v.day} (${v.jobRef})`
                    : `${cfg.label} · ${v.day}`;
                const dot = `<div style="width:15px;height:15px;border-radius:3px;flex-shrink:0;` +
                    `background:${cfg.bg};border:1.5px solid ${cfg.border};` +
                    `display:inline-flex;align-items:center;justify-content:center;` +
                    `font-size:9px;font-weight:800;color:${cfg.ic};line-height:1;" ` +
                    `title="${tipText}">${cfg.icon}</div>`;
                // Wrap in a link if we have a job URL; open in a new tab
                return v.jobUrl
                    ? `<a href="${v.jobUrl}" target="_blank" rel="noopener noreferrer" ` +
                      `class="visit-dot-link" style="text-decoration:none;display:inline-flex;">${dot}</a>`
                    : dot;
            }).join('');

            return `<td style="background:${bg};border:1px solid #f1f5f9;padding:6px 3px;` +
                `vertical-align:middle;min-width:68px;cursor:default;` +
                `${isCur ? 'outline:2px solid #0097A7;outline-offset:-2px;' : ''}">` +
                `<div style="display:flex;flex-wrap:wrap;gap:2px;justify-content:center;align-items:center;">` +
                `${dots}</div></td>`;
        }

        function renderEmptyCell() {
            return `<td style="background:#f8fafc;border:1px solid #f1f5f9;min-width:68px;"></td>`;
        }

        // ── Table body ────────────────────────────────────────────────────────
        let tableRows = '';
        for (const cat of activeCats) {
            const services = catGroups[cat.name];
            if (!services.length) continue;

            // Category header row
            tableRows += `<tr>
                <td style="position:sticky;left:0;z-index:10;
                    background:${cat.bg};color:${cat.text};
                    font-size:8px;font-weight:800;letter-spacing:0.16em;text-transform:uppercase;
                    padding:5px 14px;border-top:2px solid ${cat.accent};
                    border-right:1px solid ${cat.border};border-bottom:1px solid ${cat.border};">
                    ${esc(cat.name)}
                </td>
                ${sortedMonths.map(mk => `<td style="background:${cat.bg};
                    border-top:2px solid ${cat.accent};border-bottom:1px solid ${cat.border};
                    border-left:1px solid ${cat.border};min-width:68px;"></td>`).join('')}
            </tr>`;

            // Service rows
            for (const svc of services) {
                const cells = sortedMonths.map(mk =>
                    svc.months[mk] ? renderCell(mk, svc.months[mk]) : renderEmptyCell()
                ).join('');

                tableRows += `<tr>
                    <td style="position:sticky;left:0;z-index:10;background:#fff;
                        font-size:11.5px;font-weight:500;color:#1e293b;
                        padding:7px 10px 7px 14px;
                        border-left:3px solid ${cat.accent};
                        border-right:1px solid #e2e8f0;
                        border-bottom:1px solid #f1f5f9;
                        white-space:nowrap;overflow:hidden;max-width:240px;text-overflow:ellipsis;"
                        title="${esc(svc.desc)}">
                        ${esc(svc.desc)}
                    </td>
                    ${cells}
                </tr>`;
            }
        }

        // ── Month header cells ────────────────────────────────────────────────
        const monthHeaders = sortedMonths.map(mk => {
            const isCur = mk === thisMonthKey;
            return `<th style="background:${isCur ? '#162040' : '#09152b'};
                color:${isCur ? '#93c5fd' : '#c0cfe0'};
                font-size:10px;font-weight:600;letter-spacing:0.04em;
                padding:10px 4px;text-align:center;min-width:68px;
                border-left:1px solid #1a2e4a;border-bottom:2px solid #1a2e4a;
                white-space:nowrap;">
                ${isCur ? '<div style="font-size:7px;color:#0097A7;letter-spacing:0.14em;text-transform:uppercase;margin-bottom:2px;">NOW</div>' : ''}
                ${monthLabel(mk)}
            </th>`;
        }).join('');

        // ── Legend pills ──────────────────────────────────────────────────────
        const legendItems = [
            { icon: '–', color: '#94a3b8', label: 'Scheduled' },
            { icon: '✓', color: '#16a34a', label: 'Complete'  },
            { icon: '!', color: '#dc2626', label: 'Overdue'   },
            { icon: '◎', color: '#d97706', label: 'In Progress'},
        ].map(x => `<span style="display:inline-flex;align-items:center;gap:5px;font-size:10.5px;color:rgba(255,255,255,0.45);">
            <span style="font-weight:700;color:${x.color};">${x.icon}</span>${x.label}
        </span>`).join('');

        const catLegend = activeCats.map(c => `
            <div style="display:flex;align-items:center;gap:5px;font-size:10.5px;color:rgba(255,255,255,0.5);">
                <div style="width:8px;height:8px;border-radius:2px;background:${c.accent};flex-shrink:0;"></div>
                ${esc(c.name)}
            </div>`).join('');

        // ── Full HTML document ────────────────────────────────────────────────
        return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>${meta.planRef || 'PPM Service Planner'}${meta.ref ? ' — ' + meta.ref : ''}</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700;800&family=Open+Sans:wght@400;500;600&display=swap" rel="stylesheet">
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: 'Open Sans', Arial, sans-serif;
    background: #f0f4f8;
    min-height: 100vh;
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }
  @media print {
    .no-print { display: none !important; }
    body { background: white; }
    .page-wrap { overflow: visible; }
    /* Strip link behaviour from visit dots so PDF looks clean */
    a.visit-dot-link {
      pointer-events: none;
      cursor: default;
      text-decoration: none !important;
      color: inherit !important;
    }
  }
</style>
</head>
<body>

<!-- ══ HEADER ══════════════════════════════════════════════════════════ -->
<div style="background:linear-gradient(135deg,#09152b 0%,#0f2347 100%);color:#fff;padding:22px 28px 18px;">
  <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:20px;flex-wrap:wrap;">

    <div>
      <!-- Logo: real UP logo embedded as base64 PNG -->
      <div style="margin-bottom:8px;">
        <div style="display:inline-block;background:#fff;border-radius:7px;padding:5px 12px;line-height:0;">
          <img src="data:image/png;base64,${LOGO_B64}"
               style="height:34px;width:auto;display:block;"
               alt="Untitled Projects">
        </div>
      </div>

      <div style="font-family:'Montserrat',sans-serif;font-weight:800;font-size:20px;
        letter-spacing:-0.02em;line-height:1.2;margin-bottom:4px;color:#f1f5f9;">
        ${esc(meta.planRef || 'PPM Service Planner')}
      </div>

      <div style="font-size:10px;color:#4a6fa0;letter-spacing:0.1em;text-transform:uppercase;">
        ${meta.ref ? `<span style="color:#0097A7;font-weight:700;">${esc(meta.ref)}</span> &nbsp;·&nbsp; ` : ''}Untitled Projects Management
        ${meta.customer ? ` &nbsp;·&nbsp; ${esc(meta.customer)}` : ''}
        ${meta.site ? ` &nbsp;·&nbsp; ${esc(meta.site)}` : ''}
        ${contractPeriod ? ` &nbsp;·&nbsp; ${contractPeriod}` : ''}
      </div>

      <!-- Progress bar -->
      <div style="display:flex;align-items:center;gap:10px;margin-top:14px;">
        <div style="font-size:10.5px;color:#4a6fa0;">Overall completion</div>
        <div style="width:160px;height:5px;background:rgba(255,255,255,0.08);border-radius:99px;overflow:hidden;">
          <div style="width:${pct}%;height:100%;background:#0097A7;border-radius:99px;"></div>
        </div>
        <div style="font-size:14px;font-weight:800;color:#0097A7;font-family:'Montserrat',sans-serif;">${pct}%</div>
      </div>
    </div>

    <!-- Stats: overall + this month + print button -->
    <div style="display:flex;align-items:flex-start;gap:28px;flex-wrap:wrap;">

      <!-- Left: stacked contract total + this month -->
      <div style="display:flex;flex-direction:column;gap:16px;">

        <!-- Overall contract stats -->
        <div>
          <div style="font-size:8px;font-weight:700;letter-spacing:0.16em;text-transform:uppercase;
            color:#3d5a80;margin-bottom:10px;font-family:'Montserrat',sans-serif;">Contract Total</div>
          <div style="display:flex;gap:20px;align-items:center;">
            ${[
              { n: total,    l: 'Visits',   c: '#e2e8f0' },
              { n: complete, l: 'Complete', c: '#4ade80' },
              { n: overdue,  l: 'Overdue',  c: '#f87171' },
              { n: upcoming, l: 'Upcoming', c: '#7dd3fc' },
            ].map(({ n, l, c }) =>
              `<div style="text-align:center;width:56px;flex-shrink:0;">
                <div style="font-family:'Montserrat',sans-serif;font-size:28px;font-weight:800;color:${c};line-height:1;">${n}</div>
                <div style="font-size:8px;text-transform:uppercase;letter-spacing:0.1em;color:#3d5a80;margin-top:4px;">${l}</div>
              </div>`
            ).join('')}
            <div style="text-align:center;width:64px;flex-shrink:0;border-left:1px solid rgba(255,255,255,0.08);padding-left:16px;margin-left:4px;">
              <div style="font-family:'Montserrat',sans-serif;font-size:28px;font-weight:800;color:#0097A7;line-height:1;">${pct}%</div>
              <div style="font-size:8px;text-transform:uppercase;letter-spacing:0.1em;color:#3d5a80;margin-top:4px;">Complete</div>
            </div>
          </div>
        </div>

        <!-- This month stats (stacked below) -->
        ${thisMonthName ? `
        <div>
          <div style="font-size:8px;font-weight:700;letter-spacing:0.16em;text-transform:uppercase;
            color:#0097A7;margin-bottom:10px;font-family:'Montserrat',sans-serif;">${thisMonthName}</div>
          <div style="display:flex;gap:20px;align-items:center;">
            ${[
              { n: mTotal,    l: 'Visits',   c: '#e2e8f0' },
              { n: mComplete, l: 'Complete', c: '#4ade80' },
              { n: mOverdue,  l: 'Overdue',  c: '#f87171' },
              { n: mUpcoming, l: 'Upcoming', c: '#7dd3fc' },
            ].map(({ n, l, c }) =>
              `<div style="text-align:center;width:56px;flex-shrink:0;">
                <div style="font-family:'Montserrat',sans-serif;font-size:28px;font-weight:800;color:${c};line-height:1;">${n}</div>
                <div style="font-size:8px;text-transform:uppercase;letter-spacing:0.1em;color:#3d5a80;margin-top:4px;">${l}</div>
              </div>`
            ).join('')}
            <div style="text-align:center;width:64px;flex-shrink:0;border-left:1px solid rgba(255,255,255,0.08);padding-left:16px;margin-left:4px;">
              <div style="font-family:'Montserrat',sans-serif;font-size:28px;font-weight:800;color:#0097A7;line-height:1;">${mPct}%</div>
              <div style="font-size:8px;text-transform:uppercase;letter-spacing:0.1em;color:#3d5a80;margin-top:4px;">Complete</div>
            </div>
          </div>
        </div>` : ''}

      </div>

      <!-- Print button -->
      <button class="no-print" onclick="window.print()"
        style="align-self:flex-end;padding:7px 15px;background:rgba(255,255,255,0.07);
          border:1px solid rgba(255,255,255,0.14);border-radius:6px;color:#94a3b8;
          font-size:11px;cursor:pointer;font-family:'Open Sans',sans-serif;letter-spacing:0.02em;">
        ⎙ Print / PDF
      </button>
    </div>
  </div>
</div>

<!-- ══ LEGEND BAR ═══════════════════════════════════════════════════════ -->
<div style="background:#0c1a30;padding:8px 28px;display:flex;justify-content:space-between;
  align-items:center;flex-wrap:wrap;gap:8px;">
  <div style="display:flex;gap:18px;flex-wrap:wrap;">
    ${catLegend}
  </div>
  <div style="display:flex;gap:16px;align-items:center;flex-wrap:wrap;">
    ${legendItems}
    <span style="border-left:1px solid rgba(255,255,255,0.08);padding-left:16px;
      font-size:9px;color:rgba(255,255,255,0.25);letter-spacing:0.04em;">
      Generated ${genDate}
    </span>
  </div>
</div>

<!-- ══ MATRIX TABLE ══════════════════════════════════════════════════════ -->
<div class="page-wrap" style="overflow-x:auto;padding:14px 16px 32px;">
  <table style="border-collapse:collapse;width:100%;background:#fff;
    border-radius:10px;overflow:hidden;
    box-shadow:0 1px 3px rgba(0,0,0,.08),0 4px 20px rgba(0,0,0,.05);">
    <thead>
      <tr>
        <th style="position:sticky;left:0;z-index:20;
          background:#09152b;color:#3d5a80;
          font-size:9px;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;
          padding:11px 14px;text-align:left;min-width:220px;
          border-right:1px solid #1a2e4a;border-bottom:2px solid #1a2e4a;">
          Service
        </th>
        ${monthHeaders}
      </tr>
    </thead>
    <tbody>
      ${tableRows || '<tr><td colspan="99" style="padding:32px;text-align:center;color:#9ca3af;">No visits found — make sure the Visits tab is loaded.</td></tr>'}
    </tbody>
  </table>
</div>

<!-- ══ FOOTER ════════════════════════════════════════════════════════════ -->
<div style="padding:10px 28px 24px;display:flex;justify-content:space-between;
  font-size:10px;color:#94a3b8;flex-wrap:wrap;gap:8px;font-family:'Open Sans',sans-serif;">
  <span>
    <span style="font-family:'Montserrat',sans-serif;font-weight:700;color:#b0bec5;">
      Untitled Projects Management
    </span>
    ${meta.ref ? ` · ${esc(meta.ref)}` : ''}
    ${meta.planRef ? ` · ${esc(meta.planRef)}` : ''}
  </span>
  <span>Generated: ${genDate}</span>
</div>

<script>
  /* Remove hrefs before print so PDF has no live links; restore after */
  window.addEventListener('beforeprint', function () {
    document.querySelectorAll('a.visit-dot-link').forEach(function (a) {
      a.dataset.savedHref   = a.getAttribute('href')   || '';
      a.dataset.savedTarget = a.getAttribute('target') || '';
      a.dataset.savedRel    = a.getAttribute('rel')    || '';
      a.removeAttribute('href');
      a.removeAttribute('target');
      a.removeAttribute('rel');
    });
  });
  window.addEventListener('afterprint', function () {
    document.querySelectorAll('a.visit-dot-link').forEach(function (a) {
      if (a.dataset.savedHref)   a.setAttribute('href',   a.dataset.savedHref);
      if (a.dataset.savedTarget) a.setAttribute('target', a.dataset.savedTarget);
      if (a.dataset.savedRel)    a.setAttribute('rel',    a.dataset.savedRel);
    });
  });
</script>
</body>
</html>`;
    }

    // ─── Generate + open the report (the work formerly behind the FAB) ──────────
    let _reportBusy = false;
    async function openCustomerReport() {
        if (_reportBusy) return;
        _reportBusy = true;
        try {
            const meta   = readContractMeta();
            const visits = await readVisits();
            if (!visits.length) {
                alert('No visits found — make sure the Visits tab is open and fully loaded.');
                return;
            }
            const html = generateReport(visits, meta);
            const win  = window.open('', '_blank');
            if (!win) {
                alert('Pop-ups blocked. Please allow pop-ups for go.joblogic.com and try again.');
                return;
            }
            win.document.open();
            win.document.write(html);
            win.document.close();
        } finally {
            _reportBusy = false;
        }
    }

    // ─── Inject the dock launcher button ────────────────────────────────────────
    function injectButton() {
        jlDockButton(SCRIPT_ID, SCRIPT_LABEL, SCRIPT_COLOR, openCustomerReport);
    }

    // Boot with retries (visits tab loads asynchronously)
    function boot() {
        injectButton();
        setTimeout(injectButton, 1500);
        setTimeout(injectButton, 4000);
    }

    window.addEventListener('hashchange', () => {
        if (location.hash.includes('visit')) setTimeout(injectButton, 600);
    });

    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
    else boot();

    console.log('[PPM-Report] v2.9 loaded');
})();
